CREATE TABLE IF NOT EXISTS `secteurs` (
  `id` int(11) NOT NULL,
  `site_id` int(11) DEFAULT NULL,
  `nom` varchar(100) NOT NULL,
  `slug` varchar(120) NOT NULL,
  `ville` varchar(100) DEFAULT 'Bordeaux',
  `type_secteur` enum('quartier','commune','zone') DEFAULT 'quartier',
  `status` enum('draft','published','archived') DEFAULT 'draft',
  `meta_title` varchar(70) DEFAULT NULL,
  `meta_description` varchar(160) DEFAULT NULL,
  `meta_keywords` varchar(255) DEFAULT NULL,
  `canonical_url` varchar(255) DEFAULT NULL,
  `og_image` varchar(255) DEFAULT NULL,
  `hero_image` varchar(255) DEFAULT NULL,
  `hero_title` varchar(200) DEFAULT NULL,
  `hero_subtitle` text DEFAULT NULL,
  `hero_cta1_text` varchar(50) DEFAULT 'Voir les prix du marché',
  `hero_cta1_link` varchar(100) DEFAULT '#prix-marche',
  `hero_cta2_text` varchar(50) DEFAULT 'Estimer mon bien',
  `hero_cta2_link` varchar(100) DEFAULT '/estimation',
  `presentation` longtext CHARACTER SET utf8mb4 COLLATE utf8mb4_bin DEFAULT NULL CHECK (json_valid(`presentation`)),
  `atouts` longtext CHARACTER SET utf8mb4 COLLATE utf8mb4_bin DEFAULT NULL CHECK (json_valid(`atouts`)),
  `marche_description` longtext CHARACTER SET utf8mb4 COLLATE utf8mb4_bin DEFAULT NULL CHECK (json_valid(`marche_description`)),
  `profils_cibles` longtext CHARACTER SET utf8mb4 COLLATE utf8mb4_bin DEFAULT NULL CHECK (json_valid(`profils_cibles`)),
  `galerie` longtext CHARACTER SET utf8mb4 COLLATE utf8mb4_bin DEFAULT NULL CHECK (json_valid(`galerie`)),
  `conseils` longtext CHARACTER SET utf8mb4 COLLATE utf8mb4_bin DEFAULT NULL CHECK (json_valid(`conseils`)),
  `faq` longtext CHARACTER SET utf8mb4 COLLATE utf8mb4_bin DEFAULT NULL CHECK (json_valid(`faq`)),
  `secteurs_lies` longtext CHARACTER SET utf8mb4 COLLATE utf8mb4_bin DEFAULT NULL CHECK (json_valid(`secteurs_lies`)),
  `prix_min` int(11) DEFAULT NULL,
  `prix_max` int(11) DEFAULT NULL,
  `rendement_min` decimal(3,1) DEFAULT NULL,
  `rendement_max` decimal(3,1) DEFAULT NULL,
  `evolution_prix` varchar(20) DEFAULT NULL,
  `delai_vente` varchar(50) DEFAULT NULL,
  `latitude` decimal(10,6) DEFAULT NULL,
  `longitude` decimal(10,6) DEFAULT NULL,
  `code_postal` varchar(10) DEFAULT NULL,
  `created_at` datetime DEFAULT current_timestamp(),
  `updated_at` datetime DEFAULT current_timestamp() ON UPDATE current_timestamp(),
  `type` enum('quartier','ville','arrondissement','commune') DEFAULT 'quartier',
  `description` text DEFAULT NULL,
  `contenu` longtext DEFAULT NULL,
  `prix_moyen_m2` int(11) DEFAULT 0,
  `image` varchar(255) DEFAULT NULL,
  `actif` tinyint(1) DEFAULT 1,
  `meta_robots` varchar(50) DEFAULT 'index, follow',
  `hero_cta_text` varchar(100) DEFAULT NULL,
  `hero_cta_url` varchar(255) DEFAULT NULL,
  `content` longtext DEFAULT NULL,
  `custom_css` text DEFAULT NULL,
  `custom_js` text DEFAULT NULL,
  `ambiance` varchar(255) DEFAULT NULL,
  `prix_moyen` varchar(100) DEFAULT NULL,
  `transport` varchar(255) DEFAULT NULL,
  `header_id` int(11) DEFAULT NULL,
  `footer_id` int(11) DEFAULT NULL,
  `external_css` longtext CHARACTER SET utf8mb4 COLLATE utf8mb4_bin DEFAULT NULL CHECK (json_valid(`external_css`)),
  `external_js` longtext CHARACTER SET utf8mb4 COLLATE utf8mb4_bin DEFAULT NULL CHECK (json_valid(`external_js`)),
  `template_id` int(11) DEFAULT NULL
) ENGINE=InnoDB DEFAULT CHARSET=utf8mb4 COLLATE=utf8mb4_unicode_ci;

