INSERT INTO `secteurs` (`id`, `site_id`, `nom`, `slug`, `ville`, `type_secteur`, `status`, `meta_title`, `meta_description`, `meta_keywords`, `canonical_url`, `og_image`, `hero_image`, `hero_title`, `hero_subtitle`, `hero_cta1_text`, `hero_cta1_link`, `hero_cta2_text`, `hero_cta2_link`, `presentation`, `atouts`, `marche_description`, `profils_cibles`, `galerie`, `conseils`, `faq`, `secteurs_lies`, `prix_min`, `prix_max`, `rendement_min`, `rendement_max`, `evolution_prix`, `delai_vente`, `latitude`, `longitude`, `code_postal`, `created_at`, `updated_at`, `type`, `description`, `contenu`, `prix_moyen_m2`, `image`, `actif`, `meta_robots`, `hero_cta_text`, `hero_cta_url`, `content`, `custom_css`, `custom_js`, `ambiance`, `prix_moyen`, `transport`, `header_id`, `footer_id`, `external_css`, `external_js`, `template_id`) VALUES
(1, NULL, 'Bacalan', 'bacalan-bordeaux', 'Bordeaux', 'quartier', 'published', 'Bacalan Bordeaux : vivre et investir dans le quartier en transformatio', 'Découvrez Bacalan à Bordeaux : quartier en pleine mutation, Bassins à flot, Cité du Vin. Prix, cadre de vie, investissement immobilier.', 'bacalan bordeaux, bassins à flot, cité du vin bordeaux, investir bacalan, prix immobilier bacalan', NULL, NULL, 'https://images.unsplash.com/photo-1519501025264-65ba15a82390?q=80&w=2000', 'Bacalan : le quartier en pleine transformation au nord de Bordeaux', 'Ancien quartier portuaire devenu pôle d\'attractivité moderne avec les Bassins à flot, la Cité du Vin et de nombreux projets urbains. Un secteur à fort potentiel de valorisation.', 'Voir les prix du marché', '#prix-marche', 'Estimer mon bien à Bacalan', '/estimation', '[\"Bacalan est l\'un des quartiers les plus anciens de Bordeaux, anciennement quartier portuaire et ouvrier. Depuis les années 2010, il connaît une transformation urbaine spectaculaire avec l\'aménagement des Bassins à flot, l\'ouverture de la Cité du Vin et la création de nouveaux programmes immobiliers modernes.\",\"Aujourd\'hui, Bacalan séduit par son mélange d\'authenticité et de modernité : anciens hangars réhabilités, architecture contemporaine, bords de Garonne aménagés. Le quartier attire jeunes actifs, créatifs et investisseurs en quête de potentiel de valorisation.\",\"Entre patrimoine industriel préservé et projets urbains ambitieux, Bacalan s\'impose comme le quartier de l\'avenir à Bordeaux, avec encore de belles opportunités d\'achat et d\'investissement avant la finalisation complète de sa mutation.\"]', '[{\"icon\":\"🏗️\",\"title\":\"Transformation urbaine\",\"description\":\"Bassins à flot, nouveaux programmes immobiliers, réhabilitation du patrimoine industriel\"},{\"icon\":\"🍷\",\"title\":\"Cité du Vin\",\"description\":\"Monument emblématique qui dynamise le quartier et attire touristes et entreprises\"},{\"icon\":\"🚇\",\"title\":\"Bien desservi\",\"description\":\"Tram B, lignes de bus, accès rapide au centre-ville et à la gare\"},{\"icon\":\"💰\",\"title\":\"Potentiel de valorisation\",\"description\":\"Quartier encore accessible avec fort potentiel de plus-value à moyen\\/long terme\"},{\"icon\":\"🌊\",\"title\":\"Bords de Garonne\",\"description\":\"Quais aménagés, balades le long du fleuve, cadre de vie agréable\"},{\"icon\":\"🎨\",\"title\":\"Vie culturelle\",\"description\":\"Darwin, espaces créatifs, restaurants, bars branchés, vie nocturne\"}]', '[\"Le marché immobilier de Bacalan reste plus accessible que les quartiers centraux historiques comme les Chartrons ou Saint-Pierre, tout en offrant un cadre moderne et une forte perspective de valorisation.\",\"Les nouveaux programmes aux Bassins à flot affichent des prix entre 5 500 et 7 000 €\\/m², tandis que l\'ancien (souvent rénové) se négocie entre 4 000 et 5 500 €\\/m².\",\"La demande locative est forte et croissante, portée par les jeunes actifs et les salariés des entreprises qui s\'installent dans le secteur.\"]', '[{\"icon\":\"🎯\",\"title\":\"Jeunes actifs et couples\",\"description\":\"Quartier moderne, vie nocturne, restaurants branchés, proximité du centre. Idéal pour ceux qui recherchent un cadre urbain et dynamique.\"},{\"icon\":\"💼\",\"title\":\"Investisseurs avisés\",\"description\":\"Fort potentiel de valorisation, demande locative élevée, programmes neufs éligibles à la défiscalisation.\"},{\"icon\":\"🎨\",\"title\":\"Créatifs et entrepreneurs\",\"description\":\"Atmosphère unique avec Darwin, espaces de coworking, lofts et ateliers d\'artistes.\"}]', '[{\"url\":\"\\/assets\\/images\\/quartiers\\/bacalan-bassins.jpg\",\"alt\":\"Bassins à flot Bacalan\"},{\"url\":\"\\/assets\\/images\\/quartiers\\/bacalan-cite-vin.jpg\",\"alt\":\"Cité du Vin Bordeaux\"},{\"url\":\"\\/assets\\/images\\/quartiers\\/bacalan-quais.jpg\",\"alt\":\"Quais de Bacalan\"}]', '[{\"icon\":\"💡\",\"text\":\"Privilégiez les biens proches du tram B pour la revente.\"},{\"icon\":\"🏗️\",\"text\":\"Les programmes neufs offrent de bonnes garanties et options de défiscalisation.\"},{\"icon\":\"🔍\",\"text\":\"Vérifiez les projets urbains à venir qui peuvent impacter la valeur.\"},{\"icon\":\"📈\",\"text\":\"Le quartier continue sa mutation : investir maintenant peut être stratégique.\"},{\"icon\":\"🏠\",\"text\":\"L\'ancien rénové reste plus accessible et offre du cachet.\"}]', '[{\"question\":\"Quel est le prix au m² à Bacalan en 2025 ?\",\"answer\":\"Le prix moyen au m² à Bacalan se situe entre 4 500 € et 6 000 €. Les programmes neufs aux Bassins à flot sont plus chers (5 500-7 000 €\\/m²) tandis que l\'ancien rénové reste accessible (4 000-5 500 €\\/m²).\"},{\"question\":\"Bacalan est-il un bon investissement locatif ?\",\"answer\":\"Oui, Bacalan offre un excellent potentiel d\'investissement avec un rendement locatif entre 3,5% et 5%. La demande locative est forte grâce aux jeunes actifs et le quartier bénéficie d\'une valorisation continue.\"},{\"question\":\"Comment se déplacer depuis Bacalan ?\",\"answer\":\"Bacalan est très bien desservi par le tramway B qui relie le quartier au centre-ville en 10-15 minutes. Plusieurs lignes de bus complètent l\'offre de transport.\"},{\"question\":\"Quels sont les projets urbains à venir à Bacalan ?\",\"answer\":\"Bacalan continue sa transformation avec de nouveaux programmes immobiliers aux Bassins à flot, la poursuite de l\'aménagement des quais, et des projets de réhabilitation du patrimoine industriel.\"},{\"question\":\"Quels sont les commerces et services à Bacalan ?\",\"answer\":\"Bacalan dispose de commerces de proximité, supermarchés, restaurants, bars et cafés. Les Bassins à flot accueillent de nombreux concepts innovants.\"}]', '[\"chartrons-bordeaux\",\"bassins-a-flot-bordeaux\",\"bordeaux-lac\"]', 4500, 6000, 3.5, 5.0, '+8% sur 2 ans', '2 à 3 mois', 44.866670, -0.550000, '33300', '2026-01-28 23:51:34', '2026-01-28 23:51:34', 'quartier', NULL, NULL, 0, NULL, 1, 'index, follow', NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL),
(2, NULL, 'Bassins à Flot', 'bassins-a-flot-bordeaux', 'Bordeaux', 'quartier', 'published', 'Bassins à Flot Bordeaux : le nouveau quartier moderne de Bordeaux', 'Découvrez les Bassins à Flot à Bordeaux : quartier contemporain, Cité du Vin, programmes neufs. Prix immobilier, cadre de vie et investissement.', 'bassins à flot bordeaux, cité du vin, quartier neuf bordeaux, investir bassins à flot, prix immobilier', NULL, NULL, 'https://images.unsplash.com/photo-1545324418-cc1a3fa10c00?q=80&w=2000', 'Bassins à Flot : le quartier contemporain au bord de la Garonne', 'Éco-quartier moderne au cœur de Bordeaux, les Bassins à Flot allient architecture contemporaine, patrimoine portuaire et qualité de vie au bord de l\'eau.', 'Voir les prix du marché', '#prix-marche', 'Estimer mon bien', '/estimation', '[\"Les Bassins à Flot constituent le plus grand projet de renouvellement urbain de Bordeaux. Situé au nord de la ville, ce quartier en pleine expansion mêle harmonieusement patrimoine industriel et architecture contemporaine.\",\"Avec la Cité du Vin comme emblème, le quartier attire résidents, touristes et entreprises. Les anciens hangars sont transformés en espaces de vie, bureaux et commerces innovants.\",\"Entre les bassins historiques et les quais aménagés, le quartier offre un cadre de vie unique au bord de l\'eau, idéal pour les amateurs d\'urbanisme contemporain.\"]', '[{\"icon\":\"🏛️\",\"title\":\"Cité du Vin\",\"description\":\"Musée emblématique et attraction majeure qui dynamise tout le quartier\"},{\"icon\":\"🌿\",\"title\":\"Éco-quartier\",\"description\":\"Conception durable, espaces verts, bâtiments basse consommation\"},{\"icon\":\"🌊\",\"title\":\"Vie au bord de l\'eau\",\"description\":\"Bassins historiques, quais aménagés, terrasses et promenades\"},{\"icon\":\"🏗️\",\"title\":\"Architecture moderne\",\"description\":\"Programmes neufs design, lofts dans d\'anciens hangars réhabilités\"},{\"icon\":\"🚇\",\"title\":\"Accessibilité\",\"description\":\"Tram B, bus, pistes cyclables, proche du centre-ville\"},{\"icon\":\"🍽️\",\"title\":\"Vie de quartier\",\"description\":\"Restaurants, bars, commerces, vie nocturne animée\"}]', '[\"Le marché immobilier des Bassins à Flot est dominé par les programmes neufs de standing. Les prix sont parmi les plus élevés du nord de Bordeaux, reflet de la qualité des constructions et de l\'attractivité du quartier.\",\"La demande est très forte, notamment pour les appartements avec vue sur les bassins ou balcon. Les délais de vente sont courts pour les biens bien situés.\",\"L\'investissement locatif reste intéressant malgré les prix élevés, grâce à une demande locative soutenue par les jeunes actifs et cadres.\"]', '[{\"icon\":\"💼\",\"title\":\"Cadres et CSP+\",\"description\":\"Appartements modernes de standing, vue sur l\'eau, proximité des entreprises.\"},{\"icon\":\"🎯\",\"title\":\"Primo-accédants ambitieux\",\"description\":\"Studio ou 2 pièces en résidence neuve, idéal pour commencer.\"},{\"icon\":\"📈\",\"title\":\"Investisseurs patrimoniaux\",\"description\":\"Valorisation assurée, quartier premium, locataires de qualité.\"}]', '[{\"url\":\"\\/assets\\/images\\/quartiers\\/bassins-cite-vin.jpg\",\"alt\":\"Cité du Vin Bassins à Flot\"},{\"url\":\"\\/assets\\/images\\/quartiers\\/bassins-quais.jpg\",\"alt\":\"Quais des Bassins à Flot\"},{\"url\":\"\\/assets\\/images\\/quartiers\\/bassins-immeubles.jpg\",\"alt\":\"Immeubles modernes Bassins à Flot\"}]', '[{\"icon\":\"🌊\",\"text\":\"Privilégiez les appartements avec vue sur les bassins.\"},{\"icon\":\"🏗️\",\"text\":\"Les programmes neufs offrent garanties et équipements modernes.\"},{\"icon\":\"📍\",\"text\":\"Vérifiez la proximité du tram pour faciliter les déplacements.\"},{\"icon\":\"💰\",\"text\":\"Comparez les prestations entre promoteurs.\"},{\"icon\":\"🔮\",\"text\":\"Le quartier a encore du potentiel de développement.\"}]', '[{\"question\":\"Quel est le prix au m² aux Bassins à Flot ?\",\"answer\":\"Le prix moyen se situe entre 5 500 € et 7 000 €\\/m². Les programmes premium avec vue sur l\'eau peuvent dépasser 7 500 €\\/m².\"},{\"question\":\"Les Bassins à Flot sont-ils bien desservis ?\",\"answer\":\"Oui, le quartier est desservi par le tram B avec plusieurs stations. Le centre-ville est accessible en 10-15 minutes.\"},{\"question\":\"Y a-t-il des écoles aux Bassins à Flot ?\",\"answer\":\"De nouvelles écoles ont été construites pour accompagner le développement du quartier. D\'autres sont prévues.\"},{\"question\":\"Le quartier est-il terminé ?\",\"answer\":\"Non, les Bassins à Flot continuent leur développement avec de nouveaux programmes et aménagements prévus jusqu\'en 2030.\"},{\"question\":\"Est-ce un bon investissement ?\",\"answer\":\"Oui, malgré les prix élevés, le quartier offre une excellente valorisation et une demande locative soutenue.\"}]', '[\"bacalan-bordeaux\",\"chartrons-bordeaux\",\"bordeaux-lac\"]', 5500, 7000, 3.0, 4.5, '+10% sur 2 ans', '1 à 2 mois', 44.869440, -0.552780, '33300', '2026-01-28 23:51:34', '2026-01-28 23:51:34', 'quartier', NULL, NULL, 0, NULL, 1, 'index, follow', NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL),
(3, NULL, 'Saint-Pierre', 'saint-pierre-bordeaux', 'Bordeaux', 'quartier', 'published', 'Saint-Pierre Bordeaux : le cœur historique classé UNESCO', 'Découvrez Saint-Pierre, cœur historique de Bordeaux : Place de la Bourse, architecture XVIIIe, vie nocturne. Prix immobilier et estimation gratuite.', 'saint-pierre bordeaux, place de la bourse, centre historique bordeaux, immobilier saint-pierre, prix m2 bordeaux centre', NULL, NULL, 'https://images.unsplash.com/photo-1558618666-fcd25c85cd64?q=80&w=2000', 'Saint-Pierre : le cœur historique et vibrant de Bordeaux', 'Au pied de la Place de la Bourse, Saint-Pierre incarne l\'excellence bordelaise avec son architecture XVIIIe siècle classée UNESCO, ses places animées et sa vie nocturne effervescente.', 'Voir les prix du marché', '#prix-marche', 'Estimer mon bien', '/estimation', '[\"Saint-Pierre est le quartier le plus ancien et le plus emblématique de Bordeaux. Situé au cœur du triangle d\'or, il abrite la célèbre Place de la Bourse avec son miroir d\'eau, symbole de la renaissance bordelaise.\",\"Ses ruelles pavées, ses immeubles XVIIIe siècle et ses places animées en font un lieu de vie prisé, mêlant patrimoine historique et dynamisme contemporain. Restaurants, bars et boutiques créent une ambiance unique.\",\"Classé au patrimoine mondial de l\'UNESCO, Saint-Pierre représente l\'excellence architecturale bordelaise et attire aussi bien les résidents que les investisseurs à la recherche de biens d\'exception.\"]', '[{\"icon\":\"🏛️\",\"title\":\"Patrimoine UNESCO\",\"description\":\"Architecture XVIIIe siècle exceptionnelle, Place de la Bourse, immeubles classés\"},{\"icon\":\"🎭\",\"title\":\"Vie culturelle intense\",\"description\":\"Musées, galeries, spectacles de rue, animations permanentes\"},{\"icon\":\"🍷\",\"title\":\"Gastronomie\",\"description\":\"Restaurants étoilés, bistrots, bars à vin, terrasses animées\"},{\"icon\":\"🚶\",\"title\":\"Tout à pied\",\"description\":\"Commerces, services, transports : tout est accessible à pied\"},{\"icon\":\"🌙\",\"title\":\"Vie nocturne\",\"description\":\"Quartier le plus animé de Bordeaux le soir, places vivantes\"},{\"icon\":\"💎\",\"title\":\"Prestige\",\"description\":\"Adresse prestigieuse, biens d\'exception, forte valeur patrimoniale\"}]', '[\"Le marché immobilier de Saint-Pierre est l\'un des plus prestigieux de Bordeaux. Les biens y sont rares et recherchés, ce qui maintient les prix à un niveau élevé.\",\"Les appartements avec vue sur les quais ou la Place de la Bourse atteignent des prix exceptionnels. L\'ancien rénové avec caractère reste très demandé.\",\"L\'investissement locatif peut être intéressant pour la location saisonnière ou meublée de standing, compte tenu de l\'attractivité touristique du quartier.\"]', '[{\"icon\":\"💎\",\"title\":\"Acquéreurs patrimoniaux\",\"description\":\"Biens d\'exception, appartements historiques avec caractère et vue.\"},{\"icon\":\"🌍\",\"title\":\"Investisseurs location courte durée\",\"description\":\"Quartier touristique par excellence, forte demande de meublés.\"},{\"icon\":\"🍷\",\"title\":\"Amateurs de vie urbaine\",\"description\":\"Tout à pied, vie nocturne, restaurants, culture : pour vivre au cœur de l\'action.\"}]', '[{\"url\":\"\\/assets\\/images\\/quartiers\\/saint-pierre-bourse.jpg\",\"alt\":\"Place de la Bourse Saint-Pierre\"},{\"url\":\"\\/assets\\/images\\/quartiers\\/saint-pierre-rues.jpg\",\"alt\":\"Rues pavées Saint-Pierre\"},{\"url\":\"\\/assets\\/images\\/quartiers\\/saint-pierre-terrasses.jpg\",\"alt\":\"Terrasses Saint-Pierre Bordeaux\"}]', '[{\"icon\":\"🔍\",\"text\":\"Vérifiez l\'état des parties communes dans les immeubles anciens.\"},{\"icon\":\"🔇\",\"text\":\"Attention au bruit : privilégiez les étages élevés ou les cours intérieures.\"},{\"icon\":\"📐\",\"text\":\"Les petites surfaces sont idéales pour l\'investissement locatif.\"},{\"icon\":\"🏛️\",\"text\":\"Les biens avec éléments d\'époque (parquet, moulures) se valorisent mieux.\"},{\"icon\":\"📋\",\"text\":\"Vérifiez les règles de copropriété concernant la location saisonnière.\"}]', '[{\"question\":\"Quel est le prix au m² à Saint-Pierre ?\",\"answer\":\"Le prix moyen se situe entre 5 500 € et 8 000 €\\/m². Les biens d\'exception avec vue peuvent dépasser 10 000 €\\/m².\"},{\"question\":\"Saint-Pierre est-il bruyant ?\",\"answer\":\"C\'est un quartier animé, surtout le soir et le week-end. Les appartements en cour intérieure ou en étage élevé sont plus calmes.\"},{\"question\":\"La location saisonnière est-elle autorisée ?\",\"answer\":\"Oui, mais réglementée à Bordeaux. Vérifiez les règles en vigueur et les autorisations nécessaires.\"},{\"question\":\"Y a-t-il des écoles à Saint-Pierre ?\",\"answer\":\"Quelques écoles sont présentes dans le centre, mais les familles préfèrent souvent les quartiers périphériques plus calmes.\"},{\"question\":\"Comment se garer à Saint-Pierre ?\",\"answer\":\"Le stationnement est difficile et payant. Des parkings publics existent mais les places privatives sont rares et chères.\"}]', '[\"chartrons-bordeaux\",\"saint-michel-bordeaux\",\"hotel-de-ville-bordeaux\"]', 5500, 8000, 2.5, 4.0, '+5% sur 2 ans', '2 à 4 mois', 44.840000, -0.570000, '33000', '2026-01-28 23:51:34', '2026-01-28 23:51:34', 'quartier', NULL, NULL, 0, NULL, 1, 'index, follow', NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL),
(4, NULL, 'La Victoire', 'la-victoire-bordeaux', 'Bordeaux', 'quartier', 'published', 'La Victoire Bordeaux : quartier étudiant, central et vivant', 'Découvrez le quartier de La Victoire à Bordeaux : vie étudiante, commerces, transports, animations, marché immobilier et estimation gratuite.', 'la victoire bordeaux, quartier la victoire, vivre la victoire, prix immobilier la victoire, acheter la victoire, étudiants bordeaux', NULL, NULL, 'https://images.unsplash.com/photo-1520975918319-2b79ae3ae5f4?q=80&w=2000', 'La Victoire : le cœur étudiant et commerçant de Bordeaux', 'Animée, centrale et dynamique, La Victoire est un lieu incontournable de la vie bordelaise : place emblématique, commerces, bars, transports et ambiance étudiante.', 'Voir les prix du marché', '#prix-marche', 'Estimer mon bien', '/estimation', '[\"Situé au croisement des transports et des grandes artères commerçantes, La Victoire est l\'un des quartiers les plus animés de Bordeaux. Au pied de la célèbre Porte d\'Aquitaine, la place est entourée de cafés, restaurants, commerces et d\'une vie étudiante intense.\",\"Avec son ambiance festive, son accessibilité exceptionnelle et son dynamisme constant, La Victoire attire jeunes actifs, étudiants et investisseurs.\",\"Le quartier bénéficie d\'une très forte demande locative et d\'un potentiel intéressant pour les biens bien situés ou rénovés.\"]', '[{\"icon\":\"🎓\",\"title\":\"Vie étudiante\",\"description\":\"Proximité universités & écoles, animation constante\"},{\"icon\":\"🚇\",\"title\":\"Hyper-accessible\",\"description\":\"Tram B & C, bus, centre-ville immédiat\"},{\"icon\":\"🛍️\",\"title\":\"Commerces\",\"description\":\"Artères commerçantes, bars, restaurants, vie locale intense\"},{\"icon\":\"📍\",\"title\":\"Emplacement stratégique\",\"description\":\"Carrefour central vers Saint-Michel, Saint-Genès, Pey-Berland\"},{\"icon\":\"💼\",\"title\":\"Forte demande locative\",\"description\":\"Idéal pour investisseurs (étudiants & jeunes actifs)\"},{\"ico