(5, NULL, 'Talence', 'talence-bordeaux', 'Talence', 'commune', 'published', 'Talence - Ville étudiante et résidentielle aux portes de Bordeaux', 'Découvrez Talence, commune dynamique de la métropole bordelaise : campus universitaire, qualité de vie, marché immobilier attractif pour familles et investisseu', 'talence immobilier, vivre talence, prix m2 talence, investir talence, université bordeaux talence', NULL, NULL, 'https://images.unsplash.com/photo-1541339907198-e08756dedf3f?q=80&w=2000', 'Talence : ville étudiante et résidentielle aux portes de Bordeaux', 'Aux portes de Bordeaux, Talence allie vie étudiante, dynamisme économique et cadre résidentiel paisible. Une commune prisée pour son équilibre entre animation universitaire et qualité de vie familiale.', 'Voir les prix du marché', '#prix-marche', 'Estimer mon bien', '/estimation', '[\"Ville universitaire par excellence, Talence accueille une grande partie du campus de Bordeaux, avec ses écoles d\'ingénieurs, facultés et laboratoires. Elle séduit autant les étudiants que les familles grâce à son accessibilité et à son cadre arboré.\",\"Les espaces verts, comme le parc Peixotto, offrent un véritable havre de paix. Tandis que les nombreux commerces, marchés et restaurants animent le centre-ville. Talence réussit l\'équilibre parfait entre dynamisme urbain et atmosphère conviviale.\"]', '[{\"icon\":\"🎓\",\"title\":\"Ville Étudiante\",\"description\":\"Campus universitaire, grandes écoles, bibliothèques et résidences étudiantes\"},{\"icon\":\"🌳\",\"title\":\"Cadre de Vie Verdoyant\",\"description\":\"Le parc Peixotto, les jardins partagés et les avenues arborées\"},{\"icon\":\"🚊\",\"title\":\"Mobilité & Accessibilité\",\"description\":\"Tram B vers Bordeaux, accès rapide à la rocade, pistes cyclables\"},{\"icon\":\"🏠\",\"title\":\"Vie de quartier\",\"description\":\"Commerces, marchés, restaurants et vie associative riche\"},{\"icon\":\"👨‍👩‍👧\",\"title\":\"Familial\",\"description\":\"Écoles réputées, activités pour enfants, quartiers calmes\"},{\"icon\":\"💰\",\"title\":\"Prix attractifs\",\"description\":\"Plus accessible que Bordeaux centre avec une excellente qualité de vie\"}]', '[\"Le marché immobilier de Talence est porté par la double demande des étudiants et des familles. Les maisons de ville et appartements proches du tram trouvent rapidement preneur.\",\"Les biens destinés à la location meublée ou à la colocation sont particulièrement recherchés près du campus.\"]', '[{\"icon\":\"👨‍👩‍👧\",\"title\":\"Familles\",\"description\":\"Maisons familiales avec jardin et garage, écoles, quartiers calmes.\"},{\"icon\":\"🎓\",\"title\":\"Étudiants\",\"description\":\"Appartements et studios proches du campus et du tram.\"},{\"icon\":\"📈\",\"title\":\"Investisseurs\",\"description\":\"Rendement locatif : 4,5 à 5,5 %, demande soutenue des étudiants.\"}]', '[{\"url\":\"\\/assets\\/images\\/quartiers\\/talence-peixotto.jpg\",\"alt\":\"Parc Peixotto Talence\"},{\"url\":\"\\/assets\\/images\\/quartiers\\/talence-campus.jpg\",\"alt\":\"Campus universitaire Talence\"},{\"url\":\"\\/assets\\/images\\/quartiers\\/talence-centre.jpg\",\"alt\":\"Centre-ville Talence\"}]', '[{\"icon\":\"🚊\",\"text\":\"Privilégiez les biens proches du tram B pour la revente.\"},{\"icon\":\"🎓\",\"text\":\"Les studios près du campus sont idéaux pour l\'investissement.\"},{\"icon\":\"🏠\",\"text\":\"Les maisons avec jardin à Peixotto ou Suzon sont très recherchées.\"},{\"icon\":\"💡\",\"text\":\"La colocation offre les meilleurs rendements locatifs.\"}]', '[{\"question\":\"Quel est le prix au m² à Talence ?\",\"answer\":\"Le prix moyen se situe entre 4 000 € et 5 500 €\\/m² selon les quartiers et le type de bien.\"},{\"question\":\"Talence est-elle bien desservie ?\",\"answer\":\"Oui, le tram B relie Talence au centre de Bordeaux en 15-20 minutes. Bus et pistes cyclables complètent l\'offre.\"},{\"question\":\"Quels sont les meilleurs quartiers à Talence ?\",\"answer\":\"Peixotto, Suzon et Thouars sont les quartiers les plus recherchés pour leur cadre de vie et leur proximité des commodités.\"},{\"question\":\"L\'investissement locatif est-il intéressant à Talence ?\",\"answer\":\"Oui, avec des rendements de 4,5% à 5,5% grâce à la forte demande étudiante et une faible vacance locative.\"},{\"question\":\"Y a-t-il des écoles à Talence ?\",\"answer\":\"Oui, Talence dispose de nombreuses écoles maternelles, primaires, collèges et lycées de qualité.\"}]', '[\"pessac-bordeaux\",\"gradignan-bordeaux\",\"begles-bordeaux\"]', 4000, 5500, 4.5, 5.5, '+6% sur 2 ans', '2 à 3 mois', 44.801670, -0.590000, '33400', '2026-01-28 23:51:34', '2026-01-28 23:51:34', 'quartier', NULL, NULL, 0, NULL, 1, 'index, follow', NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL),
(6, NULL, 'Pessac', 'pessac-bordeaux', 'Pessac', 'commune', 'published', 'Pessac - Ville dynamique et familiale de Bordeaux Métropole', 'Découvrez Pessac, commune vivante de la métropole bordelaise : vie de quartier, campus universitaire, nature et marché immobilier attractif.', 'pessac immobilier, vivre pessac, prix m2 pessac, investir pessac, université bordeaux pessac', NULL, NULL, 'https://images.unsplash.com/photo-1600585154340-be6161a56a0c?q=80&w=2000', 'Pessac : ville dynamique et familiale de Bordeaux Métropole', 'Entre ville, nature et innovation, Pessac offre un équilibre parfait entre vie urbaine et cadre résidentiel. Commune phare de la métropole bordelaise.', 'Voir les prix du marché', '#prix-marche', 'Estimer mon bien', '/estimation', '[\"Pessac, située au sud-ouest de Bordeaux, est à la fois une grande commune résidentielle, un pôle universitaire majeur et un territoire économique dynamique. Elle allie vie familiale, espaces verts et infrastructures modernes.\",\"On y retrouve le campus universitaire, le domaine viticole du Château Pape Clément, plusieurs parcs, et une offre culturelle dense. Une commune attractive qui combine patrimoine, innovation et douceur de vivre.\"]', '[{\"icon\":\"📍\",\"title\":\"Proximité Bordeaux\",\"description\":\"15 min en tram ou voiture du centre de Bordeaux\"},{\"icon\":\"🎓\",\"title\":\"Campus universitaire\",\"description\":\"Écoles et centres de recherche de renom\"},{\"icon\":\"🌳\",\"title\":\"Zones verdoyantes\",\"description\":\"Quartiers résidentiels calmes et arborés\"},{\"icon\":\"🚊\",\"title\":\"Transports développés\",\"description\":\"Tram B, gare TER, bus, pistes cyclables\"},{\"icon\":\"🍷\",\"title\":\"Patrimoine viticole\",\"description\":\"Château Pape Clément et vignobles classés\"},{\"icon\":\"🎭\",\"title\":\"Culture & loisirs\",\"description\":\"Cinéma, médiathèque, théâtre, équipements sportifs\"}]', '[\"Pessac séduit par la diversité de son offre immobilière : appartements récents, maisons de ville, pavillons familiaux ou résidences étudiantes.\",\"Le secteur reste stable, soutenu par une forte demande locative et une excellente qualité de vie.\"]', '[{\"icon\":\"👨‍👩‍👧\",\"title\":\"Familles\",\"description\":\"Maisons individuelles avec jardin, quartiers Alouette, Saige, Magonty, Centre.\"},{\"icon\":\"🎓\",\"title\":\"Étudiants\",\"description\":\"Appartements modernes près du tram et du campus.\"},{\"icon\":\"📈\",\"title\":\"Investisseurs\",\"description\":\"Rendement 4 à 5%, résidences récentes, Pinel.\"}]', '[{\"url\":\"\\/assets\\/images\\/quartiers\\/pessac-pape-clement.jpg\",\"alt\":\"Château Pape Clément Pessac\"},{\"url\":\"\\/assets\\/images\\/quartiers\\/pessac-tram.jpg\",\"alt\":\"Tram B Pessac\"},{\"url\":\"\\/assets\\/images\\/quartiers\\/pessac-centre.jpg\",\"alt\":\"Centre-ville Pessac\"}]', '[{\"icon\":\"🚊\",\"text\":\"Privilégiez les biens proches du tram B pour valorisation et location.\"},{\"icon\":\"🏠\",\"text\":\"Les maisons à Alouette et Magonty sont très recherchées.\"},{\"icon\":\"🎓\",\"text\":\"La proximité du campus garantit une location rapide.\"},{\"icon\":\"💰\",\"text\":\"Résidences récentes éligibles aux dispositifs de défiscalisation.\"}]', '[{\"question\":\"Quel est le prix au m² à Pessac ?\",\"answer\":\"Le prix moyen se situe entre 3 800 € et 5 000 €\\/m² selon les quartiers.\"},{\"question\":\"Pessac est-elle bien desservie ?\",\"answer\":\"Oui, le tram B, la gare TER et les bus permettent de rejoindre Bordeaux facilement.\"},{\"question\":\"Quels sont les meilleurs quartiers ?\",\"answer\":\"Alouette, Saige, Magonty et le Centre sont les quartiers les plus recherchés.\"},{\"question\":\"L\'investissement locatif est-il rentable ?\",\"answer\":\"Oui, avec 4 à 5% de rendement et une forte demande étudiante.\"},{\"question\":\"Pessac est-elle adaptée aux familles ?\",\"answer\":\"Oui, avec des écoles réputées, des espaces verts et des quartiers calmes.\"}]', '[\"talence-bordeaux\",\"gradignan-bordeaux\",\"merignac-bordeaux\"]', 3800, 5000, 4.0, 5.0, '+5% sur 2 ans', '2 à 3 mois', 44.806670, -0.631670, '33600', '2026-01-28 23:51:34', '2026-01-28 23:51:34', 'quartier', NULL, NULL, 0, NULL, 1, 'index, follow', NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL),
(7, NULL, 'Gradignan', 'gradignan-bordeaux', 'Gradignan', 'commune', 'published', 'Gradignan - Ville verte et familiale au sud de Bordeaux', 'Découvrez Gradignan, commune verdoyante au sud de Bordeaux : qualité de vie, nature, écoles réputées et marché immobilier recherché par les familles.', 'gradignan immobilier, vivre gradignan, prix m2 gradignan, investir gradignan, bordeaux sud', NULL, NULL, 'https://images.unsplash.com/photo-1564013799919-ab600027ffc6?q=80&w=2000', 'Gradignan : ville verte et familiale au sud de Bordeaux', 'Nichée au sud-ouest de Bordeaux, Gradignan séduit par son cadre de vie verdoyant, son esprit village et ses infrastructures modernes. Une commune familiale recherchée.', 'Voir les prix du marché', '#prix-marche', 'Estimer mon bien', '/estimation', '[\"Située à seulement 20 minutes du centre de Bordeaux, Gradignan combine le confort d\'une ville à taille humaine et la proximité immédiate des grands axes de la métropole. Sa richesse en parcs, bois et ruisseaux lui vaut souvent le surnom de \\\"poumon vert\\\" du Sud Bordelais.\",\"Très prisée des familles, la commune offre un environnement sûr, des établissements scolaires réputés et un cadre résidentiel paisible, tout en restant connectée grâce au réseau de bus TBM et aux accès rapides vers Talence, Pessac et la rocade.\"]', '[{\"icon\":\"🌳\",\"title\":\"Ville Nature\",\"description\":\"Parc de Mandavit, Bois de Thouars, ruisseau du Peugue... 20 parcs et espaces boisés\"},{\"icon\":\"👨‍👩‍👧\",\"title\":\"Vie Familiale\",\"description\":\"Crèches, écoles, collèges, lycée des Graves : environnement serein\"},{\"icon\":\"🚗\",\"title\":\"Accessibilité\",\"description\":\"Accès rapide à la rocade, bus vers Bordeaux, proximité du campus\"},{\"icon\":\"🏠\",\"title\":\"Cadre verdoyant\",\"description\":\"Ville calme et familiale avec forte cohésion locale\"},{\"icon\":\"🛒\",\"title\":\"Commerces\",\"description\":\"Marchés, commerces de proximité et infrastructures sportives\"},{\"icon\":\"💰\",\"titl