(10, NULL, 'Saint-Michel', 'saint-michel-bordeaux', 'Bordeaux', 'quartier', 'published', 'Saint-Michel Bordeaux : quartier populaire et authentique', 'Découvrez Saint-Michel à Bordeaux : quartier populaire, marché animé, vie multiculturelle. Prix immobilier attractif et estimation gratuite.', 'saint-michel bordeaux, quartier saint-michel, immobilier saint-michel, marché saint-michel, prix m2 saint-michel', NULL, NULL, 'https://images.unsplash.com/photo-1600607687939-ce8a6c25118c?q=80&w=2000', 'Saint-Michel : le quartier populaire et authentique de Bordeaux', 'Quartier historique et multiculturel, Saint-Michel séduit par son authenticité, son célèbre marché et ses prix encore accessibles au cœur de Bordeaux.', 'Voir les prix du marché', '#prix-marche', 'Estimer mon bien', '/estimation', '[\"Saint-Michel est l\'un des quartiers les plus authentiques de Bordeaux. Dominé par la flèche de sa basilique, le quartier vit au rythme de son célèbre marché aux puces et de ses places animées.\",\"Quartier populaire et multiculturel, Saint-Michel connaît une gentrification progressive qui attire jeunes actifs et investisseurs à la recherche de biens à rénover.\",\"L\'ambiance unique, les prix encore accessibles et la situation centrale en font un quartier stratégique pour acheter ou investir à Bordeaux.\"]', '[{\"icon\":\"🏛️\",\"title\":\"Patrimoine\",\"description\":\"Basilique Saint-Michel, architecture historique, flèche emblématique\"},{\"icon\":\"🛒\",\"title\":\"Marché aux puces\",\"description\":\"Le plus grand marché aux puces du Sud-Ouest, institution bordelaise\"},{\"icon\":\"🌍\",\"title\":\"Multiculturel\",\"description\":\"Restaurants du monde, commerces ethniques, ambiance cosmopolite\"},{\"icon\":\"💰\",\"title\":\"Prix accessibles\",\"description\":\"Quartier central avec des prix encore abordables\"},{\"icon\":\"📍\",\"title\":\"Situation centrale\",\"description\":\"À deux pas de Saint-Pierre et des quais\"},{\"icon\":\"📈\",\"title\":\"Potentiel\",\"description\":\"Quartier en mutation avec potentiel de valorisation\"}]', '[\"Saint-Michel offre les prix les plus accessibles du centre de Bordeaux. Les immeubles anciens à rénover présentent un excellent potentiel de plus-value.\",\"Le quartier attire de plus en plus d\'investisseurs et de jeunes actifs, ce qui tire les prix à la hausse. La demande locative est forte, notamment pour les petites surfaces.\"]', '[{\"icon\":\"🎯\",\"title\":\"Jeunes actifs\",\"description\":\"Quartier central, prix accessibles, vie animée et authentique.\"},{\"icon\":\"💼\",\"title\":\"Investisseurs\",\"description\":\"Rendements élevés (4,5-6%), potentiel de plus-value, biens à rénover.\"},{\"icon\":\"🔨\",\"title\":\"Rénovateurs\",\"description\":\"Immeubles anciens avec potentiel, possibilité de division.\"}]', '[{\"url\":\"\\/assets\\/images\\/quartiers\\/saint-michel-basilique.jpg\",\"alt\":\"Basilique Saint-Michel\"},{\"url\":\"\\/assets\\/images\\/quartiers\\/saint-michel-marche.jpg\",\"alt\":\"Marché Saint-Michel\"},{\"url\":\"\\/assets\\/images\\/quartiers\\/saint-michel-places.jpg\",\"alt\":\"Places Saint-Michel\"}]', '[{\"icon\":\"🔍\",\"text\":\"Vérifiez l\'état des immeubles : certains nécessitent d\'importants travaux.\"},{\"icon\":\"📍\",\"text\":\"Les rues proches des quais sont plus cotées.\"},{\"icon\":\"🔇\",\"text\":\"Attention au bruit les jours de marché.\"},{\"icon\":\"💰\",\"text\":\"Les biens rénovés se louent très facilement.\"}]', '[{\"question\":\"Quel est le prix au m² à Saint-Michel ?\",\"answer\":\"Le prix moyen se situe entre 3 500 € et 5 000 €\\/m², ce qui en fait l\'un des quartiers centraux les plus accessibles.\"},{\"question\":\"Saint-Michel est-il sûr ?\",\"answer\":\"Le quartier a connu une amélioration ces dernières années. Comme tout quartier populaire, certaines rues sont plus calmes que d\'autres.\"},{\"question\":\"Le marché a-t-il lieu tous les jours ?\",\"answer\":\"Le grand marché aux puces a lieu le dimanche matin. Des marchés plus petits ont lieu en semaine.\"},{\"question\":\"L\'investissement est-il intéressant ?\",\"answer\":\"Oui, avec des rendements de 4,5% à 6% et un potentiel de plus-value grâce à la gentrification progressive.\"},{\"question\":\"Comment est la vie de quartier ?\",\"answer\":\"Très animée et multiculturelle. Nombreux restaurants, bars et commerces ethniques. Ambiance populaire et authentique.\"}]', '[\"saint-pierre-bordeaux\",\"la-victoire-bordeaux\",\"capucins-bordeaux\"]', 3500, 5000, 4.5, 6.0, '+7% sur 2 ans', '2 à 3 mois', 44.833330, -0.563890, '33000', '2026-01-28 23:51:34', '2026-01-28 23:51:34', 'quartier', NULL, NULL, 0, NULL, 1, 'index, follow', NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL),
(11, NULL, 'La Bastide', 'la-bastide-bordeaux', 'Bordeaux', 'quartier', 'published', 'La Bastide Bordeaux : rive droite en plein essor', 'Découvrez La Bastide à Bordeaux : rive droite dynamique, Darwin, vue sur les quais. Prix accessibles et fort potentiel de valorisation.', 'la bastide bordeaux, rive droite bordeaux, darwin bordeaux, immobilier la bastide, prix m2 la bastide', NULL, NULL, 'https://images.unsplash.com/photo-1600566753190-17f0baa2a6c3?q=80&w=2000', 'La Bastide : la rive droite en pleine renaissance', 'Face au centre historique, La Bastide s\'impose comme le quartier d\'avenir de Bordeaux avec Darwin, la vue sur les quais et des prix encore accessibles.', 'Voir les prix du marché', '#prix-marche', 'Estimer mon bien', '/estimation', '[\"La Bastide, c\'est l\'autre Bordeaux. Longtemps délaissée, la rive droite connaît depuis 15 ans une transformation spectaculaire avec le tramway, le Jardin Botanique et surtout Darwin, l\'écosystème alternatif devenu emblème du quartier.\",\"Avec sa vue imprenable sur les quais de Bordeaux, ses prix encore accessibles et son potentiel de développement, La Bastide attire investisseurs et jeunes actifs en quête d\'un cadre de vie alternatif.\",\"Entre patrimoine industriel réhabilité et projets urbains ambitieux, La Bastide s\'affirme comme le quartier stratégique pour investir à Bordeaux.\"]', '[{\"icon\":\"🌿\",\"title\":\"Darwin\",\"description\":\"Écosystème alternatif, skatepark, restaurants bio, coworking, événements\"},{\"icon\":\"🌅\",\"title\":\"Vue sur Bordeaux\",\"description\":\"Panorama exceptionnel sur les quais et le centre historique\"},{\"icon\":\"💰\",\"title\":\"Prix accessibles\",\"description\":\"Quartier central avec des prix inférieurs à la rive gauche\"},{\"icon\":\"🚊\",\"title\":\"Bien desservi\",\"description\":\"Tram A, pont de pierre, pont Chaban-Delmas\"},{\"icon\":\"🌳\",\"title\":\"Espaces verts\",\"description\":\"Jardin Botanique, parc aux Angéliques, quais aménagés\"},{\"icon\":\"📈\",\"title\":\"Fort potentiel\",\"description\":\"Quartier en mutation avec valorisation continue\"}]', '[\"Le marché immobilier de La Bastide offre les meilleurs rapports qualité-prix de Bordeaux centre. Les programmes neufs côtoient l\'ancien rénové avec des prix nettement inférieurs à la rive gauche.\",\"La demande est croissante, portée par l\'attractivité de Darwin et les projets de développement. Le potentiel de valorisation reste important.\"]', '[{\"icon\":\"🎯\",\"title\":\"Jeunes actifs\",\"description\":\"Quartier tendance, Darwin, vie alternative, prix accessibles.\"},{\"icon\":\"📈\",\"title\":\"Investisseurs\",\"description\":\"Rendements de 4 à 5,5%, fort potentiel de plus-value.\"},{\"icon\":\"👨‍👩‍👧\",\"title\":\"Familles\",\"description\":\"Espaces verts, calme, écoles, tout en restant en ville.\"}]', '[{\"url\":\"\\/assets\\/images\\/quartiers\\/la-bastide-darwin.jpg\",\"alt\":\"Darwin La Bastide\"},{\"url\":\"\\/assets\\/images\\/quartiers\\/la-bastide-quais.jpg\",\"alt\":\"Vue sur les quais La Bastide\"},{\"url\":\"\\/assets\\/images\\/quartiers\\/la-bastide-pont.jpg\",\"alt\":\"Pont de pierre La Bastide\"}]', '[{\"icon\":\"🌅\",\"text\":\"Les appartements avec vue sur Bordeaux sont très prisés.\"},{\"icon\":\"📍\",\"text\":\"Privilégiez la proximité du tram et des quais.\"},{\"icon\":\"🔮\",\"text\":\"Suivez les projets urbains : ils impactent fortement la valorisation.\"},{\"icon\":\"🏗️\",\"text\":\"Les programmes neufs offrent de belles opportunités.\"}]', '[{\"question\":\"Quel est le prix au m² à La Bastide ?\",\"answer\":\"Le prix moyen se situe entre 3 800 € et 5 500 €\\/m², ce qui reste inférieur à la rive gauche à situation équivalente.\"},{\"question\":\"La Bastide est-elle bien desservie ?\",\"answer\":\"Oui, le tram A dessert le quartier et plusieurs ponts permettent de rejoindre le centre en quelques minutes.\"},{\"question\":\"Qu\'est-ce que Darwin ?\",\"answer\":\"Darwin est un écosystème alternatif installé dans une ancienne caserne : restaurants bio, coworking, skatepark, événements culturels.\"},{\"question\":\"Le quartier a-t-il du potentiel ?\",\"answer\":\"Oui, La Bastide est considérée comme le quartier d\'avenir de Bordeaux avec de nombreux projets de développement.\"},{\"question\":\"L\'investissement est-il intéressant ?\",\"answer\":\"Oui, avec des rendements de 4 à 5,5% et un fort potentiel de valorisation grâce aux projets urbains.\"}]', '[\"cenon-bordeaux\",\"floirac-bordeaux\",\"saint-michel-bordeaux\"]', 3800, 5500, 4.0, 5.5, '+8% sur 2 ans', '2 à 3 mois', 44.841670, -0.552780, '33100', '2026-01-28 23:51:34', '2026-01-28 23:51:34', 'quartier', NULL, NULL, 0, NULL, 1, 'index, follow', NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL),
(12, NULL, 'Mérignac', 'merignac-bordeaux', 'Mérignac', 'commune', 'published', 'Mérignac - Deuxième ville de la métropole bordelaise', 'Découvrez Mérignac : aéroport, centres commerciaux, quartiers résidentiels. Prix immobilier et estimation gratuite.', 'merignac immobilier, vivre merignac, prix m2 merignac, investir merignac, aeroport bordeaux', NULL, NULL, 'https://images.unsplash.com/photo-1600585154340-be6161a56a0c?q=80&w=2000', 'Mérignac : la deuxième ville de Bordeaux Métropole', 'Avec son aéroport, ses centres commerciaux et ses quartiers résidentiels variés, Mérignac offre un cadre de vie pratique et accessible.', 'Voir les prix du marché', '#prix-marche', 'Estimer mon bien', '/estimation', '[\"Mérignac est la deuxième commune de la métropole bordelaise. Elle abrite l\'aéroport de Bordeaux-Mérignac et de nombreuses zones commerciales et d\'activités qui en font un pôle économique majeur.\",\"La ville offre des quartiers très variés : du centre-ville animé aux zones pavillonnaires calmes, en passant par des secteurs plus modernes près du tram.\"]', '[{\"icon\":\"✈️\",\"title\":\"Aéroport\",\"description\":\"Aéroport international de Bordeaux-Mérignac\"},{\"icon\":\"🛒\",\"title\":\"Commerces\",\"description\":\"Centres commerciaux, zones d\'activités, tous les services\"},{\"icon\":\"🚊\",\"title\":\"Tram\",\"description\":\"Lignes A et prolongement vers l\'aéroport\"},{\"icon\":\"🏠\",\"title\":\"Quartiers variés\",\"description\":\"Du centre animé aux quartiers pavillonnaires calmes\"},{\"icon\":\"💼\",\"title\":\"Emplois\",\"description\":\"Zones d\'activités, entreprises, aéronautique\"},{\"icon\":\"💰\",\"title\":\"Prix accessibles\",\"description\":\"Meilleur rapport qualité-prix que Bordeaux centre\"}]', '[\"Le marché immobilier de Mérignac est très varié. Les quartiers proches du tram sont les plus recherchés.\",\"Les maisons individuelles et les appartements récents trouvent facilement preneur.\"]', '[{\"icon\":\"👨‍👩‍👧\",\"title\":\"Familles\",\"description\":\"Maisons avec jardin, quartiers calmes, écoles.\"},{\"icon\":\"💼\",\"title\":\"Actifs\",\"description\":\"Proximité des zones d\'emploi et de l\'aéroport.\"},{\"icon\":\"📈\",\"title\":\"Investisseurs\",\"description\":\"Rendement 4 à 5%, demande locative soutenue.\"}]', '[{\"url\":\"\\/assets\\/images\\/quartiers\\/merignac-centre.jpg\",\"alt\":\"Centre Mérignac\"},{\"url\":\"\\/assets\\/images\\/quartiers\\/merignac-tram.jpg\",\"alt\":\"Tram Mérignac\"},{\"url\":\"\\/assets\\/images\\/quartiers\\/merignac-pavillons.jpg\",\"alt\":\"Quartier pavillonnaire Mérignac\"}]', '[{\"icon\":\"🚊\",\"text\":\"La proximité du tram est un critère clé.\"},{\"icon\":\"🔇\",\"text\":\"Vérifiez les nuisances sonores près de l\'aéroport.\"},{\"icon\":\"🏠\",\"text\":\"Les quartiers ouest sont les plus calmes.\"}]', '[{\"question\":\"Quel est le prix au m² à Mérignac ?\",\"answer\":\"Entre 3 500 € et 4 800 €\\/m² selon les quartiers.\"},{\"question\":\"Mérignac est-elle bien desservie ?\",\"answer\":\"Oui, tram A et bientôt extension vers l\'aéroport.\"},{\"question\":\"Y a-t-il du bruit de l\'aéroport ?\",\"answer\":\"Certains quartiers sont exposés. Vérifiez le PEB.\"},{\"question\":\"Quels sont les meilleurs quartiers ?\",\"answer\":\"Centre-ville, Capeyron, et les quartiers ouest sont les plus recherchés.\"}]', '[\"pessac-bordeaux\",\"cauderan-bordeaux\",\"le-bouscat-bordeaux\"]', 3500, 4800, 4.0, 5.0, '+5% sur 2 ans', '2 à 3 mois', 44.833330, -0.643330, '33700', '2026-01-28 23:51:34', '2026-01-28 23:51:34', 'quartier', NULL, NULL, 0, NULL, 1, 'index, follow', NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL),
(13, NULL, 'Le Bouscat', 'le-bouscat-bordeaux', 'Le Bouscat', 'commune', 'published', 'Le Bouscat - Commune résidentielle au nord de Bordeaux', 'Découvrez Le Bouscat : commune résidentielle, Parc Bordelais, tram. Prix immobilier et estimation gratuite.', 'le bouscat immobilier, vivre le bouscat, prix m2 le bouscat, parc bordelais, bordeaux nord', NULL, NULL, 'https://images.unsplash.com/photo-1600047509358-9dc75507daeb?q=80&w=2000', 'Le Bouscat : l\'élégance résidentielle aux portes de Bordeaux', 'Commune chic et verdoyante, Le Bouscat séduit par son cadre de vie premium, le Parc Bordelais et sa proximité immédiate du centre de Bordeaux.', 'Voir les prix du marché', '#prix-marche', 'Estimer mon bien', '/estimation', '[\"Le Bouscat est une commune résidentielle prisée au nord de Bordeaux. Elle abrite une partie du célèbre Parc Bordelais et offre un cadre de vie verdoyant et paisible.\",\"Très bien desservie par le tram, la commune attire une population aisée, séduite par ses villas, son calme et sa proximité du centre-ville.\"]', '[{\"icon\":\"🌳\",\"title\":\"Parc Bordelais\",\"description\":\"Le plus beau parc de l\'agglomération, partagé avec les Chartrons\"},{\"icon\":\"🏡\",\"title\":\"Résidentiel\",\"description\":\"Villas, maisons de caractère, quartiers calmes\"},{\"icon\":\"🚊\",\"title\":\"Tram C\",\"description\":\"Accès direct au centre de Bordeaux\"},{\"icon\":\"🛍️\",\"title\":\"Commerces\",\"description\":\"Centre-ville animé, marchés, restaurants\"},{\"icon\":\"🎓\",\"title\":\"Écoles\",\"description\":\"Établissements de qualité, vie familiale\"},{\"icon\":\"💎\",\"title\":\"Standing\",\"description\":\"Adresse prisée, biens de qualité\"}]', '[\"Le marché immobilier du Bouscat est dominé par les maisons et villas. Les prix sont élevés, reflet du standing de la commune.\",\"Les biens avec jardin proche du Parc Bordelais sont très recherchés.\"]', '[{\"icon\":\"👨‍👩‍👧\",\"title\":\"Familles aisées\",\"description\":\"Villas avec jardin, écoles, Parc Bordelais.\"},{\"icon\":\"💎\",\"title\":\"CSP+\",\"description\":\"Maisons de caractère, adresse prestigieuse.\"},{\"icon\":\"👴\",\"title\":\"Retraités\",\"description\":\"Calme, verdure, services, accessibilité.\"}]', '[{\"url\":\"\\/assets\\/images\\/quartiers\\/le-bouscat-parc.jpg\",\"alt\":\"Parc Bordelais Le Bouscat\"},{\"url\":\"\\/assets\\/images\\/quartiers\\/le-bouscat-villas.jpg\",\"alt\":\"Villas Le Bouscat\"},{\"url\":\"\\/assets\\/images\\/quartiers\\/le-bouscat-centre.jpg\",\"alt\":\"Centre Le Bouscat\"}]', '[{\"icon\":\"🌳\",\"text\":\"La proximité du Parc Bordelais fait grimper les prix.\"},{\"icon\":\"🚊\",\"text\":\"Vérifiez l\'accès au tram C.\"},{\"icon\":\"🏠\",\"text\":\"Les villas avec jardin sont les plus recherchées.\"}]', '[{\"question\":\"Quel est le prix au m² au Bouscat ?\",\"answer\":\"Entre 4 200 € et 6 000 €\\/m² selon le secteur et le type de bien.\"},{\"question\":\"Le Bouscat est-il bien desservi ?\",\"answer\":\"Oui, le tram C relie la commune au centre de Bordeaux.\"},{\"question\":\"Est-ce une commune familiale ?\",\"answer\":\"Oui, très prisée des familles aisées pour ses écoles et son cadre de vie.\"}]', '[\"chartrons-bordeaux\",\"cauderan-bordeaux\",\"bruges-bordeaux\"]', 4200, 6000, 3.0, 4.0, '+4% sur 2 ans', '2 à 4 mois', 44.862780, -0.598890, '33110', '2026-01-28 23:51:34', '2026-01-28 23:51:34', 'quartier', NULL, NULL, 0, NULL, 1, 'index, follow', NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL);


-- ------------------------------------------------------------
-- Table : local_guide
-- ------------------------------------------------------------

-- --------------------------------------------------------

--
-- Structure de la table `local_guide`
--

CREATE TABLE IF NOT EXISTS `local_guide` (
  `id` int(11) NOT NULL,
  `website_id` int(11) DEFAULT NULL,
  `name` varchar(255) NOT NULL,
  `category` varchar(50) NOT NULL,
  `specialty` varchar(255) DEFAULT NULL,
  `city` varchar(100) DEFAULT NULL,
  `address` text DEFAULT NULL,
  `phone` varchar(50) DEFAULT NULL,
  `email` varchar(255) DEFAULT NULL,
  `website` varchar(500) DEFAULT NULL,
  `description` text DEFAULT NULL,
  `logo_url` varchar(500) DEFAULT NULL,
  `rating` decimal(2,1) DEFAULT NULL,
  `status` enum('draft','published') DEFAULT 'draft',
  `display_order` int(11) DEFAULT 0,
  `created_at` timestamp NULL DEFAULT current_timestamp(),
  `updated_at` timestamp NULL DEFAULT current_timestamp() ON UPDATE current_timestamp()
) ENGINE=InnoDB DEFAULT CHARSET=utf8mb4 COLLATE=utf8mb4_general_ci;


-- ------------------------------------------------------------
-- Table : local_partners
-- ------------------------------------------------------------

-- --------------------------------------------------------

--
-- Structure de la table `local_partners`
--

CREATE TABLE IF NOT EXISTS `local_partners` (
  `id` int(11) NOT NULL,
  `website_id` int(11) DEFAULT NULL,
  `name` varchar(255) NOT NULL,
  `category` varchar(50) NOT NULL,
  `city` varchar(100) DEFAULT NULL,
  `phone` varchar(50) DEFAULT NULL,
  `email` varchar(255) DEFAULT NULL,
  `website` varchar(500) DEFAULT NULL,
  `description` text DEFAULT NULL,
  `our_link_status` enum('none','pending','active') DEFAULT 'none',
  `our_link_url` varchar(500) DEFAULT NULL,
  `backlink_status` enum('none','pending','active') DEFAULT 'none',
  `backlink_url` varchar(500) DEFAULT NULL,
  `backlink_checked_at` datetime DEFAULT NULL,
  `status` enum('active','inactive') DEFAULT 'active',
  `created_at` timestamp NULL DEFAULT current_timestamp(),
  `updated_at` timestamp NULL DEFAULT current_timestamp() ON UPDATE current_timestamp()
) ENGINE=InnoDB DEFAULT CHARSET=utf8mb4 COLLATE=utf8mb4_general_ci;


